// // This module implements a 9-bit shift register with serial load capability.
module shift_register(
    input clk,
    input rst,
    input load,
    input shift,
    input [7:0] data_in,

    output reg [7:0] data_out
);
    always @(posedge clk) begin
        if (rst) begin
            data_out <= 8'b00000000;
        end else if (load) begin
            data_out <= data_in;
        end else begin
            if (shift) begin
                data_out <= {1'b0, data_out[7:1]};
            end else begin
                data_out <= {data_out[6:0], 1'b0};
            end
        end
    end
endmodule
